// src/services/dbSimulador.js

// Estructura Jerárquica: Provincia > Ciudad > Zona > Local > Productos
export const dbSimulador = {
  // 1. OBTENER TODAS LAS OFERTAS (Para el Buscador Global)
  getOfertasGlobales: () => {
    const locales = JSON.parse(localStorage.getItem('mis-locales') || "[]");
    let todasLasOfertas = [];

    locales.forEach(local => {
      const ofertas = JSON.parse(localStorage.getItem(`ofertas-local-${local.id}`) || "[]");
      todasLasOfertas = [...todasLasOfertas, ...ofertas.map(o => ({
        ...o,
        // Inyectamos la info del Local en cada producto para el buscador
        localId: local.id,
        nombreLocal: local.nombre,
        direccionLocal: local.direccion,
        provincia: local.provincia,
        ciudad: local.ciudad,
        zona: local.zona,
        coords: local.coords
      }))];
    });
    return todasLasOfertas;
  },

  // 2. GUARDAR LOCAL (Vendedor)
  guardarLocal: (nuevoLocal) => {
    const locales = JSON.parse(localStorage.getItem('mis-locales') || "[]");
    const localConId = { ...nuevoLocal, id: Date.now().toString() };
    locales.push(localConId);
    localStorage.setItem('mis-locales', JSON.stringify(locales));
    return localConId;
  },

  // 3. GUARDAR OFERTA VINCULADA (Vendedor)
  guardarOferta: (idLocal, oferta) => {
    const clave = `ofertas-local-${idLocal}`;
    const ofertas = JSON.parse(localStorage.getItem(clave) || "[]");
    const nuevaOferta = { ...oferta, id: Date.now().toString(), localId: idLocal };
    ofertas.push(nuevaOferta);
    localStorage.setItem(clave, JSON.stringify(ofertas));
  }
};
